  "inlineSchema": "generator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"debian-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum Plan {\n  FREE\n  PRO\n  PHANTOM\n}\n\nenum Category {\n  STREAMING\n  PRODUCTIVITY\n  DESIGN\n  MUSIC\n  EDUCATION\n  UTILITIES\n}\n\nenum CookieHealth {\n  HEALTHY\n  EXPIRED\n  REFRESHING\n  UNKNOWN\n}\n\nenum TransactionStatus {\n  PENDING\n  SUCCESS\n  FAILED\n}\n\nenum UserRole {\n  USER\n  ADMIN\n}\n\nenum LoginMethod {\n  INJECT\n  INVITE_LINK\n  MANUAL\n}\n\n// ─── Users ───────────────────────────────────────────────\nmodel User {\n  id              String    @id @default(uuid())\n  email           String    @unique\n  password        String // bcrypt hashed\n  licenseKey      String?   @unique @map(\"license_key\")\n  role            UserRole  @default(USER)\n  plan            Plan      @default(FREE)\n  planExpiresAt   DateTime? @map(\"plan_expires_at\")\n  currentDeviceId String?   @map(\"current_device_id\")\n  banWarningCount Int       @default(0) @map(\"ban_warning_count\")\n  isActive        Boolean   @default(true) @map(\"is_active\")\n\n  // Referral System\n  referralCode String  @unique @map(\"referral_code\")\n  referredById String? @map(\"referred_by_id\")\n  balance      Int     @default(0)\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  sessions           Session[]\n  transactions       Transaction[]\n  referredBy         User?               @relation(\"Referral\", fields: [referredById], references: [id])\n  referrals          User[]              @relation(\"Referral\")\n  withdrawals        Withdrawal[]\n  walletTransactions WalletTransaction[]\n\n  @@map(\"users\")\n}\n\n// ─── Domains (Services like Netflix, ChatGPT, etc) ──────\nmodel Domain {\n  id           String      @id @default(uuid())\n  name         String // \"Netflix\"\n  slug         String      @unique // \"netflix\"\n  url          String // \"https://www.netflix.com\"\n  loginUrl     String?     @map(\"login_url\") // \"https://www.netflix.com/login\"\n  iconUrl      String?     @map(\"icon_url\")\n  category     Category    @default(STREAMING)\n  requiredPlan Plan        @default(FREE) @map(\"required_plan\")\n  loginMethod  LoginMethod @default(INJECT) @map(\"login_method\")\n  cookieDomain String      @map(\"cookie_domain\") // \".netflix.com\"\n  isActive     Boolean     @default(true) @map(\"is_active\")\n  createdAt    DateTime    @default(now()) @map(\"created_at\")\n  updatedAt    DateTime    @updatedAt @map(\"updated_at\")\n\n  accounts Account[]\n\n  @@map(\"domains\")\n}\n\n// ─── Premium Accounts ───────────────────────────────────\nmodel Account {\n  id                String       @id @default(uuid())\n  domainId          String       @map(\"domain_id\")\n  label             String // \"Netflix Akun 1\"\n  email             String // login email for the premium account\n  password          String // encrypted password for the premium account\n  inviteLink        String?      @map(\"invite_link\") // URL for INVITE_LINK method\n  cookies           Json? // encrypted cookie array [{name, value, domain, path, ...}]\n  localStorageData  Json?        @map(\"local_storage_data\") // encrypted local storage array [{key, value}]\n  cookieHealth      CookieHealth @default(UNKNOWN) @map(\"cookie_health\")\n  lastHealthCheck   DateTime?    @map(\"last_health_check\")\n  lastCookieSync    DateTime?    @map(\"last_cookie_sync\")\n  maxConcurrent     Int          @default(1) @map(\"max_concurrent\")\n  displayCloneCount Int          @default(1) @map(\"display_clone_count\")\n  isActive          Boolean      @default(true) @map(\"is_active\")\n  createdAt         DateTime     @default(now()) @map(\"created_at\")\n  updatedAt         DateTime     @updatedAt @map(\"updated_at\")\n\n  domain   Domain    @relation(fields: [domainId], references: [id], onDelete: Cascade)\n  sessions Session[]\n\n  @@map(\"accounts\")\n}\n\n// ─── Active Sessions (who is using which account) ───────\nmodel Session {\n  id        String   @id @default(uuid())\n  userId    String   @map(\"user_id\")\n  accountId String   @map(\"account_id\")\n  startedAt DateTime @default(now()) @map(\"started_at\")\n  expiresAt DateTime @map(\"expires_at\")\n  isActive  Boolean  @default(true) @map(\"is_active\")\n\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  account Account @relation(fields: [accountId], references: [id], onDelete: Cascade)\n\n  @@map(\"sessions\")\n}\n\n// ─── Guard Heartbeats ───────────────────────────────────\nmodel GuardHeartbeat {\n  id          String   @id @default(uuid())\n  extensionId String   @map(\"extension_id\")\n  fingerprint String?\n  isValid     Boolean  @default(true) @map(\"is_valid\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"guard_heartbeats\")\n}\n\n// ─── Transactions ────────────────────────────────────────\nmodel Transaction {\n  id            String            @id @default(uuid())\n  userId        String            @map(\"user_id\")\n  plan          Plan\n  durationDays  Int               @map(\"duration_days\")\n  amount        Int // Final amount (base + unique offset, with discount if applicable)\n  baseAmount    Int?              @map(\"base_amount\") // Original price before discount\n  uniqueOffset  Int?              @map(\"unique_offset\") // 1-99 offset added to base for uniqueness\n  qrisData      String?           @map(\"qris_data\") @db.Text // Dynamic QRIS string\n  hasDiscount   Boolean           @default(false) @map(\"has_discount\") // Did user get referral discount?\n  status        TransactionStatus @default(PENDING)\n  paymentMethod String?           @default(\"QRIS\") @map(\"payment_method\")\n  paymentUrl    String?           @map(\"payment_url\") // Kept for backward compat\n  sessionId     String?           @map(\"session_id\") // Kept for backward compat\n  createdAt     DateTime          @default(now()) @map(\"created_at\")\n  updatedAt     DateTime          @updatedAt @map(\"updated_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"transactions\")\n}\n\n// ─── Referral & Wallet ───────────────────────────────────\nenum WithdrawalStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum WalletTransactionType {\n  EARNING\n  WITHDRAWAL\n  REFUND\n}\n\nmodel Withdrawal {\n  id            String           @id @default(uuid())\n  userId        String           @map(\"user_id\")\n  amount        Int\n  status        WithdrawalStatus @default(PENDING)\n  provider      String // Gopay, Dana, Ovo, Bank Name\n  accountNumber String           @map(\"account_number\")\n  createdAt     DateTime         @default(now()) @map(\"created_at\")\n  updatedAt     DateTime         @updatedAt @map(\"updated_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"withdrawals\")\n}\n\nmodel WalletTransaction {\n  id            String                @id @default(uuid())\n  userId        String                @map(\"user_id\")\n  amount        Int\n  type          WalletTransactionType\n  description   String?\n  referenceTxId String?               @map(\"reference_tx_id\") // ID from Transaction or Withdrawal if applicable\n  createdAt     DateTime              @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"wallet_transactions\")\n}\n",
